import{_ as t,o as e,c as a,a2 as u}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"风险控制","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/风险.md","filePath":"05_quotes/by-theme/风险.md"}'),q={name:"05_quotes/by-theme/风险.md"};function r(l,o,c,p,s,_){return e(),a("div",null,[...o[0]||(o[0]=[u('<h1 id="风险控制" tabindex="-1">风险控制 <a class="header-anchor" href="#风险控制" aria-label="Permalink to &quot;风险控制&quot;">​</a></h1><blockquote><p>&quot;风险来自于你不知道自己在做什么。&quot;——巴菲特</p></blockquote><p>风险控制贯穿巴菲特整个投资生涯，是其最核心的生存哲学。</p><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;投资的第一个原则是：不要亏损。第二个原则是：永远不要忘记第一个原则。&quot;</p></blockquote><blockquote><p>&quot;我们不借款。如果我们不借钱，就不会被迫在不利时刻卖出。这是风险管理的根本。&quot;</p></blockquote><blockquote><p>&quot;要衡量风险，必须问自己：最坏的情况会发生什么？损失有多大？我们能承受吗？&quot;</p></blockquote><blockquote><p>&quot;我们不参与金融衍生品。衍生品是大规模毁灭性金融武器，即使你完全了解风险，也很难避免灾难。&quot;</p></blockquote><blockquote><p>&quot;2008年金融危机告诉我们，过度杠杆化的金融机构可以在一夜之间崩溃。资本充足率是风险的最好指标。&quot;</p></blockquote><blockquote><p>&quot;风险不是用Beta系数来衡量的。真正的风险是：本金永久损失的可能性。&quot;</p></blockquote><hr><h2 id="出处年份" tabindex="-1">出处年份 <a class="header-anchor" href="#出处年份" aria-label="Permalink to &quot;出处年份&quot;">​</a></h2><p>1993年 · 2003年 · 2008年 · 2010年 · 2014年 · 2020年</p>',14)])])}const i=t(q,[["render",r]]);export{b as __pageData,i as default};
